mapper.select:
select n.id, n.title, n.topic_name as topic, n.type, SUBSTRING_INDEX(n.img_uris, ',', 1) AS cover, DATE_FORMAT(n.create_time, '%Y-%m-%d %H:%i:%s') AS create_time, DATE_FORMAT(n.update_time, '%Y-%m-%d %H:%i:%s') AS update_time, u.nickname AS creator_nickname, u.avatar AS creator_avatar, ifnull(nc.like_total,0) as like_total, ifnull(nc.collect_total, 0) as collect_total, ifnull(nc.comment_total,0) as comment_total from t_content n left join t_user u on n.creator_id = u.id left join t_content_count nc on n.id = nc.content_id where n.visible = 0 and n.`status` = 1
and n.id = #{contentId} limit 1
and n.creator_id = #{userId}
